#include <experimental/simd>
#include <print>
namespace stdx = std::experimental;

int main() {
    stdx::fixed_size_simd<float, 4> a(1.0f);
    stdx::fixed_size_simd<float, 4> b([](int i){ return float(i + 1); });
    auto c = a + b;
    std::println("lanes: {}", stdx::fixed_size_simd<float,4>::size());
    for (int i = 0; i < 4; ++i) {
        float val = c[i];
        std::print("{} ", val);
    }
    std::println("");
    float sum = stdx::reduce(c);
    std::println("sum={}", sum);
}

#include <experimental/simd>
#include <array>
#include <print>
namespace stdx = std::experimental;

int main() {
    std::array<float, 4> data = {-1.0f, 2.0f, -3.0f, 4.0f};
    stdx::fixed_size_simd<float, 4> v;
    v.copy_from(data.data(), stdx::element_aligned);

    // clamp negatives to zero
    auto mask = v < stdx::fixed_size_simd<float, 4>(0.0f);
    stdx::where(mask, v) = stdx::fixed_size_simd<float, 4>(0.0f);

    std::array<float, 4> result;
    v.copy_to(result.data(), stdx::element_aligned);
    for (float x : result)
        std::print("{} ", x);
    std::println("");
}

