// spec-based: std::linalg not yet implemented in any compiler
#include <linalg>
#include <mdspan>
#include <vector>
#include <print>

int main() {
    // vectors
    std::vector<double> x_data = {1.0, 2.0, 3.0};
    std::vector<double> y_data = {4.0, 5.0, 6.0};
    auto x = std::mdspan(x_data.data(), 3);
    auto y = std::mdspan(y_data.data(), 3);

    double d = std::linalg::dot(x, y);  // 1*4 + 2*5 + 3*6 = 32
    std::println("dot = {}", d);

    // matrix-vector: A·x -> r
    // identity matrix 3×3, row-major
    std::vector<double> A_data = {1,0,0,  0,1,0,  0,0,1};
    auto A = std::mdspan(A_data.data(), 3, 3);

    std::vector<double> result(3);
    auto r = std::mdspan(result.data(), 3);
    std::linalg::matrix_vector_product(A, x, r);

    std::print("A·x = ");
    for (double v : result) std::print("{} ", v);
    std::println("");
}

// spec-based: std::linalg not yet implemented in any compiler
#include <linalg>
#include <mdspan>
#include <vector>
#include <print>

int main() {
    // 2×3 matrix, row-major
    std::vector<double> data = {1,2,3,  4,5,6};
    auto A  = std::mdspan(data.data(), 2, 3);  // 2 rows, 3 cols
    auto At = std::linalg::transposed(A);      // 3 rows, 2 cols; no copy

    std::println("A[0,1] = {}  At[1,0] = {}",
                 A[0,1], At[1,0]);             // same cell: 2

    std::println("A  extents: {}x{}", A.extent(0),  A.extent(1));
    std::println("At extents: {}x{}", At.extent(0), At.extent(1));

    // lazy scaled view: 2·A (read-only)
    auto twoA = std::linalg::scaled(2.0, A);
    std::println("2·A[0,0] = {}", twoA[0,0]);  // 2*1 = 2
    std::println("2·A[1,2] = {}", twoA[1,2]);  // 2*6 = 12
}

