int main() {
    unsigned int x = 0b10110101u;
    std::println("popcount: {}", std::popcount(x));
    std::println("leading zeros: {}", std::countl_zero(x));
    std::println("is power of 2: {}", std::has_single_bit(x));

    unsigned int y = 64u; // 0b01000000
    std::println("popcount(64): {}", std::popcount(y));
    std::println("is power of 2(64): {}", std::has_single_bit(y));
}

#include <bit>
#include <print>

int main() {
    unsigned int x = 5u;
    std::println("bit_ceil(5): {}", std::bit_ceil(x));     // next power of 2 >= 5
    std::println("bit_floor(5): {}", std::bit_floor(x));   // largest power of 2 <= 5
    std::println("bit_width(5): {}", std::bit_width(x));   // bits needed to represent 5

    unsigned char b = 0b10110001u;
    std::println("rotl(0b10110001, 2): {:08b}", std::rotl(b, 2));
    std::println("rotr(0b10110001, 2): {:08b}", std::rotr(b, 2));
}

